SourceCode.Declaration:
/// <summary>
/// Request data contract carrying the note ID of the note header to look up.
/// </summary>
[DataContractAttribute]
class ConDemoNoteLookupRequest
{
    Num noteId;
}

Method.Source:
[DataMemberAttribute('NoteId')]
public Num parmNoteId(Num _noteId = noteId)
{
    noteId = _noteId;
    return noteId;
}
